from typing import List

class Solution:
    def solve(self, nums: List[int]) -> int:
        n = len(nums)
        result = 1
        for i in range(20, -1, -1):
            max_count = 0
            min_count = float('inf')
            for j in range(n):
                if (nums[j] >> i) & 1:
                    max_count += 1
                else:
                    min_count = min(min_count, max_count)
            result += max(max_count - n // 2, 0)
        return result

