#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    int solve(vector<int>& nums) {
        int n = nums.size();
        int result = 1;
        for (int i = 20; i >= 0; i--) {
            int max_count = 0;
            int min_count = INT_MAX;
            for (int j = 0; j < n; j++) {
                if (nums[j] >> i & 1) {
                    max_count++;
                }
                else {
                    min_count = min(min_count, max_count);
                }
            }
            result += max(max_count - n / 2, 0);
        }
        return result;
    }
};
